import { useState } from "react";
import { useNavigate } from "react-router-dom";
import PhoneFrame from "../components/PhoneFrame";
import ProgressBar from "../components/ProgressBar";

const opts = [
  { icon: "🚶", bg: true, name: "Walking + auto", chip: "Recommended", sub: "Best for most Manali sightseeing spots", price: "₹200/day" },
  { icon: "🚕", bg: false, name: "Cab (Ola / Uber)", sub: "Comfortable, on-demand", price: "₹600/day" },
  { icon: "🛵", bg: false, name: "Bike rental", sub: "Explore at your own pace", price: "₹450/day" },
  { icon: "🚌", bg: false, name: "Public transport", sub: "HRTC buses, shared cabs", price: "₹80/day" },
];

const Local = () => {
  const [selected, setSelected] = useState(0);
  const navigate = useNavigate();
  return (
    <PhoneFrame time="9:49">
      <div className="app-header">
        <span className="back-link" onClick={() => navigate("/food")}>← Back</span>
        <span className="logo-text">travel<span className="logo-dot">blurry</span></span>
        <span className="header-action" onClick={() => navigate("/plan")}>Skip all</span>
      </div>

      <div className="content-scroll">
        <ProgressBar doneCount={4} />
        <div className="screen-title">Local travel</div>
        <div className="screen-sub">How will you get around in Manali?</div>

        {opts.map((o, i) => (
          <div key={i} className={`local-opt${selected === i ? " selected" : ""}`} onClick={() => setSelected(i)}>
            <div className={`travel-opt-icon${o.bg ? " blue-bg" : ""}`} style={{ fontSize: 16 }}>{o.icon}</div>
            <div className="travel-opt-info">
              <div className="travel-opt-name">{o.name}{o.chip && <span className="rec-chip">{o.chip}</span>}</div>
              <div className="travel-opt-sub">{o.sub}</div>
            </div>
            <div><div className="travel-opt-price">{o.price}</div></div>
            <div className={`radio-circle${selected === i ? " on" : ""}`}></div>
          </div>
        ))}
      </div>

      <div className="sticky-bottom">
        <button className="cta-btn" onClick={() => navigate("/loading")}>Build my plan →</button>
        <div className="skip-link" onClick={() => navigate("/plan")}>Skip this step</div>
      </div>
    </PhoneFrame>
  );
};

export default Local;
